mapper.insert:
INSERT INTO t_owners_assembly_package_material (package_id, tenant_id, material_id)
SELECT #{packageId}, #{tenantId}, material_id
FROM t_owners_assembly_material
WHERE material_id = #{materialId}
  AND tenant_id = #{tenantId}
  AND session_id = (
      SELECT session_id
      FROM t_owners_assembly_package
      WHERE package_id = #{packageId}
        AND tenant_id = #{tenantId}
  )

mapper.update:
UPDATE t_owners_assembly_package
SET status = 'VOTING',
    update_time = CURRENT_TIMESTAMP
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND status = 'PUBLIC_NOTICE'

UPDATE t_owners_assembly_package
SET status = 'SETTLED',
    update_time = CURRENT_TIMESTAMP
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND status = 'VOTING'

mapper.select:
SELECT MIN(participated_at)
FROM (
    SELECT create_time AS participated_at
    FROM t_owners_assembly_vote_record
    WHERE package_id = #{packageId}
      AND tenant_id = #{tenantId}
      AND uid = #{uid}
      AND valid_flag = 1
    UNION ALL
    SELECT ballot.cast_at AS participated_at
    FROM t_voting_execution_package execution_package
    JOIN t_voting_ballot_record ballot
      ON ballot.package_id = execution_package.package_id
     AND ballot.tenant_id = execution_package.tenant_id
    JOIN t_voting_electorate_item_snapshot electorate_item
      ON electorate_item.snapshot_item_id = ballot.electorate_item_id
    WHERE execution_package.business_type = 'OWNERS_ASSEMBLY'
      AND execution_package.business_reference_id = #{packageId}
      AND execution_package.tenant_id = #{tenantId}
      AND electorate_item.representative_uid = #{uid}
      AND ballot.valid_flag = 1
) participation

SELECT NOT EXISTS (
    SELECT 1
    FROM t_owners_assembly_subject s
    LEFT JOIN t_voting_result r ON r.subject_id = s.subject_id
    WHERE s.package_id = #{packageId}
      AND s.tenant_id = #{tenantId}
      AND COALESCE(r.passed, 0) != 1
)
